Based on the reference materials and detailed specifications, here's the complete implementation of the `delete_inactive_users` function:

```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace delete_inactive_users {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::optional<sqlgen::DateTime> last_login;
  std::string status = "active";
};

int delete_inactive_users() {
  using namespace sqlgen::literals;

  // 1. Connect to the SQLite database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return conn_result.error().what();
  }
  auto conn = conn_result.value();

  // 2. Begin a transaction
  auto transaction_result = sqlgen::begin_transaction(conn);
  if (!transaction_result) {
    return transaction_result.error().what();
  }
  auto transaction = transaction_result.value();

  // 3. Create delete statement with condition
  auto condition = "last_login"_c < "2025-01-01";
  auto delete_stmt = sqlgen::delete_from<User> | sqlgen::where(condition);

  // 4. Execute the delete operation within the transaction
  auto delete_result = delete_stmt(conn);
  if (!delete_result) {
    // Rollback on failure
    auto rollback_result = transaction.rollback();
    if (!rollback_result) {
      return rollback_result.error().what();
    }
    return delete_result.error().what();
  }

  // 5. Commit the transaction
  auto commit_result = transaction.commit();
  if (!commit_result) {
    return commit_result.error().what();
  }

  // 6. Return operation result of commit
  return commit_result.value() ? 0 : 1;
}

} // namespace delete_inactive_users
```

