std::vector<CourseStats> query_course_enrollment_stats() {
  // 1. Connect to the SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // 2. Create Course and Enrollment tables
  conn.execute(sqlgen::sqlite::to_sql(sqlgen::create_table<Course>));
  conn.execute(sqlgen::sqlite::to_sql(sqlgen::create_table<Enrollment>));

  // 3. Build the query using sqlgen's fluent interface
  using namespace sqlgen::literals;
  auto query = sqlgen::select_from<Course>("title")
               .left_join<Enrollment>("course_id")
               .group_by("course_id", "title")
               .agg(sqlgen::count("enrollment_id").as("student_count"),
                      sqlgen::avg("grade").as("avg_grade"));

  // 4. Execute the query and return results
  auto result = query.read<std::vector<CourseStats>>(conn);

