  EXPECT_EQ(result[0].total_revenue, 50.0);

  EXPECT_EQ(result[1].product_name, "Widget B");
  EXPECT_EQ(result[1].total_quantity, 1);
  EXPECT_EQ(result[1].total_revenue, 20.0);
}

