namespace upsert_inventory_items {

struct Inventory {
  sqlgen::PrimaryKey<int> item_id;
  std::string name;
  int quantity;
};

bool upsert_inventory_items(const std::vector<Inventory>& items) {
  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }
  auto conn = conn_result.value();

  // Perform the upsert
  auto write_result = sqlgen::write<Inventory>(conn, items, true);
  if (!write_result) {
    return false;
  }

  // Read all items
  auto read_result = sqlgen::read<std::vector<Inventory>>(conn);
  if (!read_result) {
    return false;
  }
  auto read_items = read_result.value();

  // Create a map of input items by item_id
  std::unordered_map<int, const Inventory*> input_map;
  for (const auto& item : items) {
    input_map[item.item_id] = &item;
  }

  // Check each read item against the input map
  for (const auto& read_item : read_items) {
    auto it = input_map.find(read_item.item_id);
    if (it == input_map.end()) {
      // Extra item in database, but we ignore it
      continue;
    }
    const auto& input_item = it->second;
    if (read_item.name != input_item->name || read_item.quantity != input_item->quantity) {
      return false;
    }
    // Remove from map to check if all input items are present
    input_map.erase(it);
  }

  // Check if any input items were not found in the database
  if (input_map.size() != 0) {
    return false;
  }

  return true;
}

}  // namespace upsert_inventory_items

