#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace analyze_social_network {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::string email;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> join_date;
  std::optional<std::string> city;
};

struct Friendship {
  sqlgen::ForeignKey<User, "user_id"> user1_id;
  sqlgen::ForeignKey<User, "user_id"> user2_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> created_at;
  sqlgen::PrimaryKey<user1_id, user2_id> primary;
};

struct FriendConnection {
  std::string user1_name;
  std::string user2_name;
};

std::vector<FriendConnection> analyze_social_network_impl(const std::vector<User>& users, const std::vector<Friendship>& friendships) {
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Create tables
  conn.execute(sqlgen::create_table<User>);
  conn.execute(sqlgen::create_table<Friendship>);

  // Insert data
  conn.insert(users.begin(), users.end());
  conn.insert(friendships.begin(), friendships.end());

  // Query 1: Mutual Friends
  auto mutual_query = sqlgen::select_from<User, Friendship, Friendship, User>(
      "u1", "f1", "f2", "u2")
      .fields("u1.username", "u2.username")
      .joins(
          sqlgen::join("f1", "u1.user_id = f1.user_id1"),
          sqlgen::join("f2", "f1.user_id2 = f2.user_id1"),
          sqlgen::join("u2", "f2.user_id2 = u2.user_id")
      )
      .where("u1.user_id < u2.user_id")
      .where(sqlgen::exists(sqlgen::select_from<Friendship>("f3")
          .where("f3.user_id1 = u1.user_id AND f3.user_id2 = u2.user_id")))
      .group_by("u1.user_id", "u2.user_id")
      .having("COUNT(f1.user_id2) > 0")
      .to<std::vector<FriendConnection>>;

  auto mutual_result = conn.read(mutual_query);

  // Query 2: Users with more than average friends
  auto avg_subquery = sqlgen::select_from<Friendship>()
      .group_by("user_id1")
      .agg(sqlgen::count("*").as("friend_count"));

  auto avg_users_query = sqlgen::select_from<User>("u")
      .left_join<Friendship>("f", "u.user_id = f.user_id1")
      .group_by("u.user_id", "u.username")
      .agg(sqlgen::count("f.user_id2").as("friend_count"))
      .having("friend_count > (SELECT AVG(friend_count) FROM (" + avg_subquery.to_sql() + ") AS subq)")
      .order_by(sqlgen::desc("friend_count"));

  // Query 3: Friend-of-friend
  auto foaf_query = sqlgen::select_from<User, Friendship, Friendship, User>(
      "u1", "f1", "f2", "u3")
      .fields("u1.username", "u3.username")
      .joins(
          sqlgen::join("f1", "u1.user_id = f1.user_id1"),
          sqlgen::join("f2", "f1.user_id2 = f2.user_id1"),
          sqlgen::join("u3", "f2.user_id2 = u3.user_id")
      )
      .where("u1.user_id != u3.user_id")
      .where(sqlgen::not_exists(sqlgen::select_from<Friendship>("f3")
          .where("f3.user_id1 = u1.user_id AND f3.user_id2 = u3.user_id")
          .or_where("f3.user_id1 = u3.user_id AND f3.user_id2 = u1.user_id")))
      .group_by("u1.user_id", "u3.user_id")
      .having("COUNT(DISTINCT f2.user_id1) = 1");

  // Query 4: Most connected users
  auto friends_count_query = sqlgen::select_from<User, Friendship>(
      "u", "f")
